import React, { useMemo } from 'react';
import { Link, NavLink } from 'react-router-dom';

function chunk(arr, size) {
    const out = [];
    for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
    return out;
}

export default function Header({ title, subtitle, sections }) {
    const topicLinks = useMemo(() => {
        const list = (sections || []).map(s => ({
            id: s.id,
            label: s.title,
            to: `/topic/${s.id}`,
        }));
        return chunk(list, 4); // multi-row like the screenshot
    }, [sections]);

    return (
        <header className="header">
            <div className="container headerInner headerInnerGrid">
                <div className="brand">
                    <Link className="brandLink" to="/">
                        <div className="brandTitle">{title}</div>
                        <div className="brandSubtitle">{subtitle}</div>
                    </Link>
                </div>

                <nav className="navMega" aria-label="UGAC navigation">
                    {topicLinks.map((row, idx) => (
                        <div key={idx} className="navRow">
                            {row.map(item => (
                                <NavLink key={item.id} className="navLink" to={item.to}>
                                    {item.label}
                                </NavLink>
                            ))}
                        </div>
                    ))}
                    <div className="navRow">
                        <NavLink className="navLink" to="/announcements">
                            Announcements
                        </NavLink>
                        <NavLink className="navLink" to="/contacts">
                            Contacts
                        </NavLink>
                    </div>
                </nav>
            </div>
        </header>
    );
}
